using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF 9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents remain queryable.
            b.HasDiscriminator<string>("Discriminator");

            // EF 9 dropped the discriminator prefix from the JSON id ("Product|123" → "123").
            // Preserve the old format so existing documents are still found by id.
            b.HasDiscriminatorInJsonId();

            // EF 9 maps the key property directly to the JSON "id" and drops the
            // separate shadow __id property. Existing documents still store "Id" as
            // a distinct JSON field alongside "id"; keep a shadow id so nothing breaks.
            b.HasShadowId();
        });

        // HasIndex was removed — Cosmos indexes all properties by default.
        // Manage custom indexing policies through the Azure Portal instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

